1	/** A live cell's position as [x, y] coordinates. */
2	export type Cell = [number, number];
3	
4	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
5	  [-1, -1], [-1, 0], [-1, 1],
6	  [ 0, -1],          [ 0, 1],
7	  [ 1, -1], [ 1, 0], [ 1, 1],
8	];
9	
10	const keyOf = ([x, y]: Cell): string => `${x},${y}`;
11	
12	/**
13	 * Computes the next generation of Conway's Game of Life.
14	 * Returns the set of cells that will be alive in the next tick.
15	 */
16	export function nextGeneration(cells: Cell[]): Cell[] {
17	  const alive = new Set(cells.map(keyOf));
18	  const neighborCounts = countNeighbors(cells);
19	
20	  return [...neighborCounts]
21	    .filter(([k, { count }]) => count === 3 || (count === 2 && alive.has(k)))
22	    .map(([, { cell }]) => cell);
23	}
24	
25	function countNeighbors(cells: Cell[]): Map<string, { cell: Cell; count: number }> {
26	  const counts = new Map<string, { cell: Cell; count: number }>();
27	  for (const [x, y] of cells) {
28	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
29	      const neighbor: Cell = [x + dx, y + dy];
30	      const k = keyOf(neighbor);
31	      const entry = counts.get(k);
32	      if (entry) {
33	        entry.count++;
34	      } else {
35	        counts.set(k, { cell: neighbor, count: 1 });
36	      }
37	    }
38	  }
39	  return counts;
40	}
